import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API = "http://localhost:3000/api";
const FASALLADA = ["Xadaano", "1aad", "2aad", "3aad", "4aad", "5aad", "6aad", "7aad", "8aad", "9aad", "10aad", "11aad", "12aad"];
const WEEK_DAYS = ["Sabti", "Axad", "Isniin", "Talaado", "Arbaco", "Khamiis"];

// MADOOYINKA OO DHAMMAYSTIRAN
const SUBJECTS = {
  "Xadaano": ["Hifdi", "Farshaxan", "Xisaab Mini", "Af-Somali", "English Mini", "Tacliim"],
  "Primary": ["Af-Somali", "Carabi", "Xisaab", "Tarbiya", "Saynis", "English", "Social Studies", "Juqraafi"],
  "Secondary": ["Math", "Physics", "Chemistry", "Biology", "English", "Af-Somali", "Carabi", "History", "Geography", "Culuunta Diinta"]
};

export default function App() {
  const [user, setUser] = useState(null);
  const [allStudents, setAllStudents] = useState([]);
  const [view, setView] = useState("classes");
  const [activeFasal, setActiveFasal] = useState("");
  const [adminTab, setAdminTab] = useState("attendance");
  const [studentTab, setStudentTab] = useState("exam");
  const [form, setForm] = useState({ id: "", pass: "" });
  const [search, setSearch] = useState("");
  const [showAttButtons, setShowAttButtons] = useState(false);

  useEffect(() => { if (user?.role === 'admin') load(); }, [user]);
  const load = () => axios.get(`${API}/data`).then(res => setAllStudents(res.data));

  const login = () => {
    axios.post(`${API}/login`, form).then(res => setUser(res.data)).catch(() => alert("ID ama Pass waa khaldan yahay!"));
  };

  const sync = (data) => { setAllStudents(data); axios.post(`${API}/update`, data); };

  const addStudent = (f) => {
    const n = prompt("Magaca Saddexan:");
    const meel = prompt("Ku dhashay (City):");
    const aTel = prompt("Tel Aabbaha:");
    const hTel = prompt("Tel Hooyada:");
    const id = prompt("ID-ga Ardayga:");
    if(n && id) {
      const s = { id, pass: "123", magaca: n, meel, aaboTel: aTel, hooyoTel: hTel, fasalka: f, exams: {}, att: {}, fee: "Ma bixin" };
      sync([...allStudents, s]);
    }
  };

  const getSubjects = (f) => {
    if (f === "Xadaano") return SUBJECTS["Xadaano"];
    if (["1aad", "2aad", "3aad", "4aad", "5aad", "6aad", "7aad", "8aad"].includes(f)) return SUBJECTS["Primary"];
    return SUBJECTS["Secondary"];
  };

  const changeAdminPass = () => {
    const p = prompt("Geli Password-ka cusub ee Admin-ka:");
    if(p) axios.post(`${API}/change-admin-pass`, { newPass: p }).then(() => alert("Password-ka waa la beddelay!"));
  };

  if (!user) return (
    <div style={st.loginBg}><div style={st.card}>
      <h1 style={{color:'#1a2a6c', marginBottom:'5px'}}>NAWAWI SCHOOL</h1>
      <p style={{fontSize:'12px', color:'#7f8c8d', marginBottom:'20px'}}>MAAMULKA IYO ARDAYDA</p>
      <input style={st.in} placeholder="Admin ID / Student ID" onChange={e => setForm({...form, id: e.target.value})} />
      <input style={st.in} type="password" placeholder="Password" onChange={e => setForm({...form, pass: e.target.value})} />
      <button style={st.btn} onClick={login}>SOO GAL</button>
    </div></div>
  );

  return (
    <div style={{display:'flex', height:'100vh', background:'#f0f2f5', fontFamily:'Arial'}}>
      {/* SIDEBAR */}
      <div style={st.sidebar}>
        <div style={st.profile}>
          <div style={st.avatar}>🏫</div>
          <h3>NAWAWI</h3>
          <p style={{fontSize:'11px', opacity:0.6}}>{user.magaca}</p>
        </div>
        <div style={st.nav}>
          {user.role === 'admin' ? (
            <>
              <button style={st.navBtn} onClick={() => { setView("classes"); setShowAttButtons(false); }}>🏠 Dashboard</button>
              <button style={st.navBtn} onClick={() => setAdminTab("attendance")}>📅 Xadiris</button>
              <button style={st.navBtn} onClick={() => setAdminTab("exams")}>📝 Imtixaanada</button>
              <button style={st.navBtn} onClick={() => setAdminTab("fees")}>💰 Lacagaha</button>
              <button style={{...st.navBtn, color:'#f1c40f'}} onClick={changeAdminPass}>⚙️ Beddel Pass</button>
            </>
          ) : (
            <>
              <button style={st.navBtn} onClick={() => setStudentTab("attendance")}>📅 My Attendance</button>
              <button style={st.navBtn} onClick={() => setStudentTab("exam")}>📝 My Grades</button>
            </>
          )}
        </div>
        <button style={st.out} onClick={() => setUser(null)}>Logout</button>
      </div>

      {/* MAIN CONTENT */}
      <div style={{flex:1, padding:'40px', overflowY:'auto'}}>
        {user.role === 'admin' ? (
          view === "classes" ? (
            <div style={st.grid}>
              {FASALLADA.map(f => (
                <div key={f} style={st.classBox} onClick={() => { setActiveFasal(f); setView("list"); }}>
                  <h2 style={{margin:0, color:'#1a2a6c'}}>{f}</h2>
                  <p style={{fontSize:'12px', color:'#7f8c8d'}}>{allStudents.filter(s => s.fasalka === f).length} Arday</p>
                  <button style={st.addBtn} onClick={(e) => { e.stopPropagation(); addStudent(f); }}>+ Ku dar Arday</button>
                </div>
              ))}
            </div>
          ) : (
            <div style={st.whiteCard}>
              <div style={{display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'20px'}}>
                <button onClick={() => setView("classes")} style={st.backBtn}>← Back</button>
                <input style={st.search} placeholder="Raadi magaca ardayga..." onChange={e => setSearch(e.target.value)} />
                {adminTab === "attendance" && (
                  <button onClick={() => setShowAttButtons(!showAttButtons)} 
                    style={{...st.toggleBtn, background: showAttButtons ? '#e74c3c' : '#27ae60'}}>
                    {showAttButtons ? "Close Attendance" : "Open Attendance Mode"}
                  </button>
                )}
              </div>

              <h2 style={{color:'#1a2a6c', borderLeft:'5px solid #1a2a6c', paddingLeft:'15px'}}>{activeFasal} - {adminTab.toUpperCase()}</h2>

              <div style={{overflowX:'auto'}}>
              <table style={st.table}>
                <thead>
                  <tr style={st.thead}>
                    <th>ID</th><th>Magaca Ardayga</th>
                    {adminTab === "exams" ? getSubjects(activeFasal).map(m => <th key={m} style={{fontSize:'11px'}}>{m}</th>) : <th>Action</th>}
                  </tr>
                </thead>
                <tbody>
                  {allStudents.filter(s => s.fasalka === activeFasal && s.magaca.toLowerCase().includes(search.toLowerCase())).map(s => (
                    <tr key={s.id} style={st.tr}>
                      <td><b>{s.id}</b></td>
                      <td style={{textAlign:'left'}}>{s.magaca}</td>
                      {adminTab === "exams" ? (
                        getSubjects(activeFasal).map(m => (
                          <td key={m}>
                            <input style={st.markIn} defaultValue={s.exams[m] || ""} 
                            onBlur={(e) => { s.exams[m] = e.target.value; sync([...allStudents]); }} />
                          </td>
                        ))
                      ) : (
                        <td>
                          {adminTab === "attendance" && showAttButtons && (
                            <div style={{display:'flex', gap:'5px', justifyContent:'center'}}>
                              <button style={st.pBtn} onClick={() => { s.att[WEEK_DAYS[new Date().getDay()]] = "√"; sync([...allStudents]); }}>√ Sax</button>
                              <button style={st.aBtn} onClick={() => { s.att[WEEK_DAYS[new Date().getDay()]] = "X"; sync([...allStudents]); }}>X Qalad</button>
                            </div>
                          )}
                          {adminTab === "attendance" && !showAttButtons && <span style={{color:'#bdc3c7'}}>🔒 Locked</span>}
                          {adminTab === "fees" && <select value={s.fee} onChange={(e) => { s.fee = e.target.value; sync([...allStudents]); }} style={st.sel}><option>Ma bixin</option><option>Bixiyey</option></select>}
                          <button onClick={() => {if(window.confirm('Ma hubtaa?')) sync(allStudents.filter(x => x.id !== s.id))}} style={st.del}>Del</button>
                        </td>
                      )}
                    </tr>
                  ))}
                </tbody>
              </table>
              </div>
            </div>
          )
        ) : (
          /* STUDENT VIEW */
          <div style={st.stuCard}>
            <h1 style={{color:'#1a2a6c'}}>Nawawi Portal: {user.magaca}</h1>
            <div style={st.infoGrid}>
                <div style={st.infoItem}><b>Fasalka:</b> {user.fasalka}</div>
                <div style={st.infoItem}><b>Dhalasho:</b> {user.meel}</div>
                <div style={st.infoItem}><b>Tel Aabo:</b> {user.aaboTel}</div>
            </div>
            {studentTab === "exam" && (
              <div style={{marginTop:'30px'}}>
                <h3>📝 Natiijada Imtixaanka</h3>
                <div style={st.markGrid}>
                  {getSubjects(user.fasalka).map(m => (
                    <div key={m} style={st.markBox}><b>{m}</b><br/><span style={{fontSize:'20px', color:'#2980b9'}}>{user.exams[m] || "0"}</span></div>
                  ))}
                </div>
              </div>
            )}
            {studentTab === "attendance" && (
              <div style={{marginTop:'30px'}}>
                <h3>📅 Xadiriskaaga Asbuuca</h3>
                <div style={st.attGrid}>
                  {WEEK_DAYS.map(day => (
                    <div key={day} style={{...st.dayBox, 
                      background: user.att[day] === "√" ? '#2ecc71' : user.att[day] === "X" ? '#e74c3c' : '#fff',
                      color: user.att[day] ? '#fff' : '#000'
                    }}><b>{day}</b><br/>{user.att[day] || "-"}</div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

const st = {
  loginBg: { height:'100vh', display:'flex', justifyContent:'center', alignItems:'center', background:'#0aec4aff' },
  card: { background:'white', padding:'45px', borderRadius:'15px', textAlign:'center', width:'350px', boxShadow:'0 10px 30px rgba(0,0,0,0.2)' },
  in: { display:'block', width:'100%', padding:'12px', margin:'10px 0', borderRadius:'8px', border:'1px solid #ddd' },
  btn: { width:'100%', padding:'12px', background:'#1a2a6c', color:'white', border:'none', borderRadius:'8px', cursor:'pointer', fontWeight:'bold' },
  sidebar: { width:'240px', background:'#213e5aff', color:'white', padding:'30px', display:'flex', flexDirection:'column' },
  profile: { textAlign:'center', marginBottom:'40px', borderBottom:'1px solid #2c3e50', paddingBottom:'20px' },
  avatar: { fontSize:'50px' },
  nav: { flex:1 },
  navBtn: { display:'block', width:'100%', padding:'12px', background:'transparent', border:'none', color:'#bdc3c7', textAlign:'left', cursor:'pointer', borderRadius:'8px' },
  out: { padding:'12px', background:'#e74c3c', color:'white', border:'none', borderRadius:'8px' },
  grid: { display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(180px, 1fr))', gap:'20px' },
  classBox: { background:'white', padding:'25px', borderRadius:'15px', textAlign:'center', cursor:'pointer', borderBottom:'5px solid #1a2a6c', boxShadow:'0 4px 6px rgba(0,0,0,0.05)' },
  addBtn: { background:'#d512f3e0', color:'white', border:'none', padding:'5px 10px', borderRadius:'5px', marginTop:'10px', fontSize:'11px' },
  whiteCard: { background:'white', padding:'40px', borderRadius:'15px', boxShadow:'0 5px 20px rgba(0,0,0,0.05)' },
  backBtn: { background:'#eee', border:'none', padding:'8px 20px', borderRadius:'8px', cursor:'pointer' },
  search: { padding:'10px', width:'250px', borderRadius:'8px', border:'1px solid #ddd' },
  toggleBtn: { color:'white', border:'none', padding:'10px 20px', borderRadius:'8px', cursor:'pointer', fontWeight:'bold' },
  table: { width:'100%', borderCollapse:'collapse' },
  thead: { background:'#f8f9fa', height:'50px' },
  tr: { borderBottom:'1px solid #eee', height:'65px', textAlign:'center' },
  markIn: { width:'45px', padding:'5px', textAlign:'center', border:'1px solid #ddd', borderRadius:'4px' },
  pBtn: { background:'#2ecc71', color:'white', border:'none', padding:'6px 12px', borderRadius:'5px' },
  aBtn: { background:'#e74c3c', color:'white', border:'none', padding:'6px 12px', borderRadius:'5px' },
  del: { color:'red', border:'none', background:'none', cursor:'pointer', marginLeft:'10px' },
  sel: { padding:'5px', borderRadius:'4px', border:'1px solid #c03030ff' },
  stuCard: { background:'white', padding:'40px', borderRadius:'20px' },
  infoGrid: { display:'flex', gap:'20px', background:'#dc12e7ff', padding:'20px', borderRadius:'12px' },
  markGrid: { display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(120px, 1fr))', gap:'15px' },
  markBox: { background:'white', padding:'15px', borderRadius:'10px', border:'1px solid #eee', textAlign:'center' },
  attGrid: { display:'grid', gridTemplateColumns:'repeat(6, 1fr)', gap:'10px' },
  dayBox: { padding:'15px 5px', textAlign:'center', borderRadius:'10px', border:'1px solid #eeeeeeff' }
};
